+const tocStart = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEnd = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^(?: {0,3})(#{1,6})[ \	]+(.+?)\\s*$/;
