+/** Generates a table of contents inside an opt-in `<!-- toc -->` section. */
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const start = lines.findIndex((line) => tocStart.test(line));
+    if (start === -1) return text;
+
+    let end = -1;
+    for (let index = start + 1; index < lines.length; index++) {
+      if (tocEnd.test(lines[index])) {
+        end = index;
+        break;
+      }
+    }
+
+    const tocEndIndex = end === -1 ? lines.length : end;
+    const headings = this.getHeadings(lines, start, tocEndIndex, options);
+    const generatedToc = this.buildToc(lines[start], end === -1 ? '<!-- /toc -->' : lines[end], headings, options);
+    const before = lines.slice(0, start);
+    const after = end === -1 ? [] : lines.slice(end + 1);
+
+    // The generated TOC always ends in a blank line. Remove old boundary blank
+    // lines so repeated runs remain stable.
+    while (after.length > 0 && after[0].trim() === '') after.shift();
+    return [...before, generatedToc, ...after].join('\
');
+  }
+
+  private getHeadings(lines: string[], tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): Heading[] {
+    const anchors = new Map<string, number>();
+    const headings: Heading[] = [];
+    for (let index = 0; index < lines.length; index++) {
+      if (index >= tocStartIndex && index <= tocEndIndex) continue;
+      const match = lines[index].match(atxHeading);
+      if (!match) continue;
+
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) continue;
+
+      const rawText = stripHeadingSuffix(match[2]);
+      const explicitId = rawText.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/);
+      const headingText = explicitId ? rawText.slice(0, explicitId.index).trimEnd() : rawText;
+      if (isExcluded(headingText, options.excludeHeadings)) continue;
+
+      const baseAnchor = options.useExplicitIds && explicitId ? explicitId[1] : makeAnchor(headingText);
+      const count = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, count + 1);
+      const anchor = count === 0 ? baseAnchor : `${baseAnchor}-${count}`;
+      const displayText = options.stripFormattingInToc ? stripFormatting(headingText) : headingText;
+      headings.push({level, text: displayText, anchor});
+    }
+    return headings;
+  }
+
+  private buildToc(startMarker: string, endMarker: string, headings: Heading[], options: AutoTocOptions): string {
+    const title = options.title.trim();
+    const body: string[] = [startMarker, ''];
+    if (title) body.push(title, '');
