+    for (let index = 0; index < headings.length; index++) {
+      const heading = headings[index];
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      body.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
+    }
